{"type": "post", "post": {"team": "sales", "channel": "sales_updates", "user": "julian_lee", "message": "Good morning team, we have a team meeting scheduled for 2 PM today to discuss the sales performance of Q1. Please ensure to review the sales figures beforehand.", "created_at": 1620500000000}}
{"type": "post", "post": {"team": "sales", "channel": "sales_updates", "user": "emily_smith", "message": "Thanks for the reminder, Julian. I'll prepare a detailed analysis of the sales data for the meeting.", "created_at": 1620501000000}}
