{"type": "post", "post": {"team": "partnerships", "channel": "pharmacy_partnerships", "user": "mark_watson", "message": "We have a meeting with potential partners tomorrow. I'll need all hands on deck to prepare the necessary documents.", "created_at": 1620503000000}}
