{"type": "post", "post": {"team": "sales", "channel": "sales_updates", "user": "julian_lee", "message": "Team, we are also planning a training session next week on our new CRM tool. More details will be shared soon.", "created_at": 1620505000000}}
{"type": "post", "post": {"team": "sales", "channel": "sales_updates", "user": "emily_smith", "message": "That sounds great, Julian. Looking forward to the training session.", "created_at": 1620506000000}}
